-- Alan Turing (1–16)
(gen_random_uuid(), 'Solo podemos ver poco hacia adelante, pero podemos ver mucho de lo que necesita hacerse.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'Una máquina merecería llamarse inteligente si pudiera engañar a un humano haciéndole creer que es humano.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),
(gen_random_uuid(), 'A veces son las personas de las que nadie espera nada quienes hacen las cosas que nadie puede imaginar.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','perseverance'], true, 'science'),
(gen_random_uuid(), 'Quienes pueden imaginar cualquier cosa pueden crear lo imposible.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'La pregunta no es si las máquinas pueden pensar, sino si los hombres lo hacen.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'La ciencia es una ecuación diferencial; la religión es una condición de frontera.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),
(gen_random_uuid(), 'El razonamiento matemático puede considerarse como el ejercicio de una combinación de ingenio y paciencia.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'Si se espera que una máquina sea infalible, no puede ser también inteligente.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'La pregunta original de si las máquinas pueden pensar es demasiado imprecisa para merecer discusión.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),
(gen_random_uuid(), 'Las máquinas me sorprenden con mucha frecuencia.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'No estamos interesados en el hecho de que el cerebro tenga la consistencia de la papilla fría.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),
(gen_random_uuid(), 'Una computadora no es inteligente a menos que pueda imitar el pensamiento humano.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),
(gen_random_uuid(), 'Podemos llamar inteligencia a todo aquello que un algoritmo puede aprender a hacer mejor que un humano.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','curiosity'], true, 'science'),
(gen_random_uuid(), 'El aprendizaje automático es la ciencia de hacer que las computadoras actúen sin ser programadas explícitamente.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','logic'], true, 'science'),
(gen_random_uuid(), 'El código es poesía ejecutable; cada línea es una decisión que moldea la realidad digital.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','logic'], true, 'science'),
(gen_random_uuid(), 'La inteligencia artificial comenzará donde termina la rigidez de nuestras propias suposiciones.', 'Alan Turing', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),

-- Ada Lovelace (17–30)
(gen_random_uuid(), 'La imaginación es la facultad del descubrimiento por excelencia. Es lo que penetra en los mundos invisibles que nos rodean.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'El motor analítico no tiene pretensiones de originar nada. Puede hacer lo que sabemos ordenarle que haga.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','curiosity'], true, 'science'),
(gen_random_uuid(), 'La ciencia de las operaciones, tal como surge de las matemáticas, es la ciencia de sí misma.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','logic'], true, 'science'),
(gen_random_uuid(), 'Nunca paro hasta que logro lo que quiero; no hay límites para lo que yo puedo hacer.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['perseverance','focus'], true, 'science'),
(gen_random_uuid(), 'El número es el único lenguaje universal que las máquinas y los humanos comparten.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','learning'], true, 'science'),
(gen_random_uuid(), 'Las matemáticas son el lenguaje con el que el universo escribe sus leyes más profundas.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),
(gen_random_uuid(), 'Toda máquina comienza como un sueño en la mente de quien se atreve a imaginar lo imposible.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','perseverance'], true, 'science'),
(gen_random_uuid(), 'Mi cerebro es más que meramente mortal; de eso estoy bastante segura.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','perseverance'], true, 'science'),
(gen_random_uuid(), 'La poesía científica y la poesía literaria no son tan distintas como la gente supone.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'Aquella que puede abstraer las relaciones más complejas tiene la clave del progreso técnico.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','learning'], true, 'science'),
(gen_random_uuid(), 'La computación no es solo aritmética; es el arte de transformar problemas en soluciones paso a paso.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','creativity'], true, 'science'),
(gen_random_uuid(), 'El futuro pertenece a quienes entienden que los números son la nueva escritura del mundo.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','curiosity'], true, 'science'),
(gen_random_uuid(), 'Una mente analítica ve patrones donde otros solo ven caos.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','wisdom'], true, 'science'),
(gen_random_uuid(), 'Para programar el futuro hay que entender primero el presente con absoluta claridad.', 'Ada Lovelace', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','learning'], true, 'science'),

-- Nikola Tesla (31–44)
(gen_random_uuid(), 'El presente es suyo; el futuro, por el cual realmente he trabajado, es mío.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['perseverance','wisdom'], true, 'science'),
(gen_random_uuid(), 'Si quieres encontrar los secretos del universo, piensa en términos de energía, frecuencia y vibración.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'Nuestra mayor ignorancia es la ignorancia de lo que ignoramos.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'La mente es como un paracaídas: solo funciona cuando está abierta.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'El día en que captemos la ciencia detrás del relámpago lo habremos dominado todo.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','perseverance'], true, 'science'),
(gen_random_uuid(), 'No me preocupo por el dinero; me preocupa el trabajo que no he podido terminar.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['focus','perseverance'], true, 'science'),
(gen_random_uuid(), 'Seré recordado por haber dotado de electricidad al mundo; aún no he empezado.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['perseverance','courage'], true, 'science'),
(gen_random_uuid(), 'La electricidad no es solo una fuente de luz; es el lenguaje del cosmos hecho visible.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'La soledad es la fuente de toda verdadera creatividad y de todo gran descubrimiento.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','reflection'], true, 'science'),
(gen_random_uuid(), 'He construido, inventado y descubierto para dar a la humanidad una vida más fácil y digna.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['perseverance','wisdom'], true, 'science'),
(gen_random_uuid(), 'La energía del futuro no vendrá del petróleo; vendrá del sol, el viento y la tierra misma.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'Un inventor es el que ve lo que todos han visto y piensa lo que nadie ha pensado.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'Lo que hoy parece ciencia ficción mañana será simplemente ciencia.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'El cerebro no es más que una computadora hecha de carne; tarde o temprano haremos máquinas que lo superen.', 'Nikola Tesla', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),

-- Steve Jobs (45–60)
(gen_random_uuid(), 'La innovación distingue a los líderes de los seguidores.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','leadership'], true, 'science'),
(gen_random_uuid(), 'La tecnología no tiene sentido por sí sola. Es la fe en la humanidad, el arte, la poesía y el amor lo que hace que la tecnología valga la pena.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','wisdom'], true, 'science'),
(gen_random_uuid(), 'Sé hambriento, sé ingenuo.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','perseverance'], true, 'science'),
(gen_random_uuid(), 'La creatividad consiste en conectar cosas. Cuando preguntas a personas creativas cómo hicieron algo, se sienten un poco culpables porque no lo hicieron realmente.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'El diseño no es solo cómo se ve; diseño es cómo funciona.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','focus'], true, 'science'),
(gen_random_uuid(), 'Tu tiempo es limitado, así que no lo malgastes viviendo la vida de otra persona.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','focus'], true, 'science'),
(gen_random_uuid(), 'Los mejores publicistas son quienes toman algo complicado y lo hacen simple.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','focus'], true, 'science'),
(gen_random_uuid(), 'Estoy convencido de que la mitad de lo que separa a los emprendedores exitosos de los que no lo son es pura perseverancia.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['perseverance','courage'], true, 'science'),
(gen_random_uuid(), 'Tenemos que tener mucho cuidado de no ahogar la chispa de la curiosidad con demasiada estructura.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','creativity'], true, 'science'),
(gen_random_uuid(), 'La calidad es más importante que la cantidad. Un jonrón es mejor que dos dobles.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['focus','wisdom'], true, 'science'),
(gen_random_uuid(), 'No puedes unir los puntos mirando hacia adelante; solo puedes hacerlo mirando hacia atrás.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','reflection'], true, 'science'),
(gen_random_uuid(), 'Poner en el mercado ideas brillantes no significa nada si no se ejecutan.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['focus','perseverance'], true, 'science'),
(gen_random_uuid(), 'El ordenador personal es la bicicleta para la mente humana.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'En un mundo conectado, la diferencia entre un mediocre y un genio es solo la calidad de su curiosidad.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'Cuando los buenos artistas copian, los grandes artistas roban. Y nosotros siempre hemos sido descarados al robar grandes ideas.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','learning'], true, 'science'),
(gen_random_uuid(), 'Simplicity is the ultimate sophistication — la simplicidad es la máxima sofisticación.', 'Steve Jobs', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['focus','creativity'], true, 'science'),

