(gen_random_uuid(), 'La tecnología solo es una herramienta. En cuanto a motivar a los niños y hacer el trabajo con ellos, el profesor es lo más importante.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','wisdom'], true, 'science'),
