(gen_random_uuid(), 'En esta era digital, la educación no puede quedarse atrás. Aprender a programar es tan fundamental como leer.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','curiosity'], true, 'science'),
