(gen_random_uuid(), 'La inteligencia artificial es la frontera más emocionante de la humanidad desde la revolución industrial.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'El software es una gran combinación entre arte y tecnología.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['creativity','curiosity'], true, 'science'),
(gen_random_uuid(), 'Sé amable con los nerds. Existen probabilidades de que acabes trabajando para uno de ellos.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','learning'], true, 'science'),
(gen_random_uuid(), 'Internet es el primer gran avance de la humanidad desde el libro impreso.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'El ciberespacio no tiene fronteras geográficas, pero sí consecuencias muy reales.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','curiosity'], true, 'science'),
(gen_random_uuid(), 'El mundo no te debe nada. Existía primero.', 'Bill Gates', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','reflection'], true, 'science'),
