-- Tim Berners-Lee (75–86)
(gen_random_uuid(), 'La web es más una creación social que técnica. La diseñé para un efecto social, no como un juguete tecnológico.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','wisdom'], true, 'science'),
(gen_random_uuid(), 'Los datos son el petróleo del siglo XXI, pero a diferencia del petróleo, pueden compartirse sin agotarse.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'La web debe ser para todos, sin barreras de lengua, cultura o capacidad.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','learning'], true, 'science'),
(gen_random_uuid(), 'Internet es un espacio público global; protegerlo es proteger la democracia misma.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','wisdom'], true, 'science'),
(gen_random_uuid(), 'Cualquier persona cuyas ideas puedan conectar con las tuyas a través de una red transforma tu capacidad de pensar.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'El objetivo de la web es servir a la humanidad; cuando lo olvidamos, nos perdemos.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','reflection'], true, 'science'),
(gen_random_uuid(), 'El hipertexto fue la clave: conectar documentos para conectar personas.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','creativity'], true, 'science'),
(gen_random_uuid(), 'La privacidad es un derecho humano fundamental que la tecnología debe proteger, no erosionar.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','wisdom'], true, 'science'),
(gen_random_uuid(), 'Un internet abierto es una oportunidad para cada persona en el planeta de aprender, crear e innovar.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','curiosity'], true, 'science'),
(gen_random_uuid(), 'Diseñé la web para que fuera una herramienta de paz y comprensión; aún creo que puede serlo.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','perseverance'], true, 'science'),
(gen_random_uuid(), 'El código abierto es la filosofía más poderosa que ha producido la era digital.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','creativity'], true, 'science'),
(gen_random_uuid(), 'Cuando compartimos conocimiento libremente en la red, todos nos volvemos más inteligentes.', 'Tim Berners-Lee', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','wisdom'], true, 'science'),

-- Grace Hopper (87–98)
(gen_random_uuid(), 'La frase más peligrosa en el idioma es: siempre lo hemos hecho así.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','wisdom'], true, 'science'),
(gen_random_uuid(), 'Va a la cama cuando quieras; aprende cuando quieras; sé curioso cuando quieras. Pero hazlo.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','perseverance'], true, 'science'),
(gen_random_uuid(), 'Si tienes una buena idea, ponla en marcha. Es mucho más fácil pedir perdón que pedir permiso.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','perseverance'], true, 'science'),
(gen_random_uuid(), 'Los humanos son alérgicos al cambio; les gusta decir que siempre lo han hecho así. Yo intento combatir eso.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','wisdom'], true, 'science'),
(gen_random_uuid(), 'El liderazgo es comprensión de personas.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','leadership'], true, 'science'),
(gen_random_uuid(), 'Uno de los errores más dañinos que puedes cometer en un equipo es creer que la idea del otro siempre vale menos.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['wisdom','learning'], true, 'science'),
(gen_random_uuid(), 'En ciencias de la computación, los barcos en el puerto están seguros, pero no es para eso para lo que se construyen los barcos.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['courage','perseverance'], true, 'science'),
(gen_random_uuid(), 'Los mejores programadores no son los que más saben; son los que mejor preguntan.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','learning'], true, 'science'),
(gen_random_uuid(), 'Una máquina solo puede hacer lo que le digamos; su inteligencia es el reflejo de la nuestra.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','wisdom'], true, 'science'),
(gen_random_uuid(), 'El aprendizaje es una aventura continua; quien deja de aprender deja de crecer.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['learning','perseverance'], true, 'science'),
(gen_random_uuid(), 'El software sin documentación es como una ciudad sin señales de tráfico: funciona hasta que falla.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['logic','wisdom'], true, 'science'),
(gen_random_uuid(), 'La computación es más que calcular; es una manera de pensar sobre el mundo.', 'Grace Hopper', 'philosophy', 'es', 'down', 'free', false, 'science', 'technology', ARRAY['curiosity','logic'], true, 'science'),

-- Arthur C. Clarke (99–110)
